import{_ as e,o as i,c as o,O as t}from"./chunks/framework.bdcb0ee1.js";const u=JSON.parse('{"title":"Moderation","description":"","frontmatter":{},"headers":[],"relativePath":"administration/moderation/moderation.md","filePath":"administration/moderation/moderation.md","lastUpdated":1773166218000}'),a={name:"administration/moderation/moderation.md"},n=t('<h1 id="moderation" tabindex="-1">Moderation <a class="header-anchor" href="#moderation" aria-label="Permalink to &quot;Moderation&quot;">​</a></h1><p>ForumSpark provides a range of moderation tools that allow administrators and moderators to manage content across your board. These tools are accessible directly from the forum and topic views.</p><nav class="table-of-contents"><ul><li><a href="#topic-moderation">Topic Moderation</a><ul><li><a href="#approving-topics">Approving Topics</a></li><li><a href="#closing-and-opening-topics">Closing and Opening Topics</a></li><li><a href="#pinning-and-unpinning-topics">Pinning and Unpinning Topics</a></li><li><a href="#moving-topics">Moving Topics</a></li><li><a href="#merging-topics">Merging Topics</a></li><li><a href="#deleting-topics">Deleting Topics</a></li></ul></li><li><a href="#reply-moderation">Reply Moderation</a><ul><li><a href="#approving-replies">Approving Replies</a></li><li><a href="#editing-replies">Editing Replies</a></li><li><a href="#deleting-replies">Deleting Replies</a></li></ul></li><li><a href="#bulk-moderation">Bulk Moderation</a></li><li><a href="#moderation-queue">Moderation Queue</a></li><li><a href="#moderator-groups">Moderator Groups</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="topic-moderation" tabindex="-1">Topic Moderation <a class="header-anchor" href="#topic-moderation" aria-label="Permalink to &quot;Topic Moderation&quot;">​</a></h2><p>Moderators have access to the following actions on individual topics:</p><h3 id="approving-topics" tabindex="-1">Approving Topics <a class="header-anchor" href="#approving-topics" aria-label="Permalink to &quot;Approving Topics&quot;">​</a></h3><p>When <strong>Require admin approval</strong> is enabled in <a href="/administration/config/settings.html">Board Settings</a>, new topics are held in a moderation queue until approved.</p><ul><li>Pending topics are highlighted and visible only to moderators and the topic author.</li><li>From the topic page, click <strong>Approve</strong> to publish the topic and make it visible to all users.</li></ul><h3 id="closing-and-opening-topics" tabindex="-1">Closing and Opening Topics <a class="header-anchor" href="#closing-and-opening-topics" aria-label="Permalink to &quot;Closing and Opening Topics&quot;">​</a></h3><ul><li><strong>Close</strong>: Locks a topic so that no further replies can be posted. The topic remains visible and readable.</li><li><strong>Open</strong>: Reopens a previously closed topic, allowing replies again.</li></ul><p>Closed topics display a lock indicator in the topic listing.</p><h3 id="pinning-and-unpinning-topics" tabindex="-1">Pinning and Unpinning Topics <a class="header-anchor" href="#pinning-and-unpinning-topics" aria-label="Permalink to &quot;Pinning and Unpinning Topics&quot;">​</a></h3><ul><li><strong>Pin</strong>: Pins a topic to the top of the forum listing, above all other topics.</li><li><strong>Unpin</strong>: Returns a pinned topic to its normal position in the listing.</li></ul><p>Pinned topics are useful for important announcements or sticky threads that should always be visible.</p><h3 id="moving-topics" tabindex="-1">Moving Topics <a class="header-anchor" href="#moving-topics" aria-label="Permalink to &quot;Moving Topics&quot;">​</a></h3><p>Move a topic from one forum to another. This is useful when a user posts in the wrong section.</p><ol><li>From the topic, click the <strong>Move</strong> option.</li><li>Select the destination forum.</li><li>Confirm the move.</li></ol><p>The topic and all its replies are moved to the new forum.</p><h3 id="merging-topics" tabindex="-1">Merging Topics <a class="header-anchor" href="#merging-topics" aria-label="Permalink to &quot;Merging Topics&quot;">​</a></h3><p>Merge two topics into one. This combines the replies from both topics into a single thread.</p><ol><li>From the topic you want to merge, click <strong>Merge</strong>.</li><li>Select the target topic to merge into.</li><li>Confirm the merge.</li></ol><p>All replies from both topics will be combined into the target topic.</p><h3 id="deleting-topics" tabindex="-1">Deleting Topics <a class="header-anchor" href="#deleting-topics" aria-label="Permalink to &quot;Deleting Topics&quot;">​</a></h3><p>Topics can be deleted by moderators. Deleted topics are soft-deleted and removed from public view.</p><h2 id="reply-moderation" tabindex="-1">Reply Moderation <a class="header-anchor" href="#reply-moderation" aria-label="Permalink to &quot;Reply Moderation&quot;">​</a></h2><h3 id="approving-replies" tabindex="-1">Approving Replies <a class="header-anchor" href="#approving-replies" aria-label="Permalink to &quot;Approving Replies&quot;">​</a></h3><p>When approval is required, individual replies are also held in a moderation queue. Moderators can approve pending replies from the topic view to make them visible.</p><h3 id="editing-replies" tabindex="-1">Editing Replies <a class="header-anchor" href="#editing-replies" aria-label="Permalink to &quot;Editing Replies&quot;">​</a></h3><p>Moderators can edit any reply. An edit notice is displayed on the post showing when it was last edited.</p><h3 id="deleting-replies" tabindex="-1">Deleting Replies <a class="header-anchor" href="#deleting-replies" aria-label="Permalink to &quot;Deleting Replies&quot;">​</a></h3><p>Moderators can delete individual replies from a topic. Deleted replies are soft-deleted and removed from public view.</p><h2 id="bulk-moderation" tabindex="-1">Bulk Moderation <a class="header-anchor" href="#bulk-moderation" aria-label="Permalink to &quot;Bulk Moderation&quot;">​</a></h2><p>From the forum listing, moderators can select multiple topics and perform actions on them at once using the <strong>bulk moderation toolbar</strong>.</p><p>Available bulk actions include:</p><ul><li>Close selected topics</li><li>Pin selected topics</li><li>Move selected topics</li><li>Delete selected topics</li><li>Apply <a href="/administration/config/automod.html">AutoMod</a> rules to selected topics</li></ul><p>To use bulk moderation:</p><ol><li>Navigate to a forum listing.</li><li>Use the checkboxes to select one or more topics.</li><li>Choose an action from the moderator toolbar at the bottom of the page.</li></ol><h2 id="moderation-queue" tabindex="-1">Moderation Queue <a class="header-anchor" href="#moderation-queue" aria-label="Permalink to &quot;Moderation Queue&quot;">​</a></h2><p>When user approval is enabled, pending topics and replies are visible in a moderation queue. Administrators and moderators can access this from the forum view to see all content awaiting approval.</p><p>Pending content is highlighted to distinguish it from approved content.</p><h2 id="moderator-groups" tabindex="-1">Moderator Groups <a class="header-anchor" href="#moderator-groups" aria-label="Permalink to &quot;Moderator Groups&quot;">​</a></h2><p>Moderator permissions are assigned at the group level. When editing a forum section, you can designate one or more groups as moderators for that specific forum.</p><p>Users in moderator groups have elevated privileges within their assigned forums, including the ability to approve, close, pin, move, merge, and delete content.</p><p>See <a href="/administration/structure/section-management.html">Section Management</a> for details on assigning moderator groups.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Moderation actions are available inline from the topic and forum views — there is no separate moderation panel.</li><li>Only users with the appropriate group permissions will see moderation controls.</li><li>Closing a topic does not affect its visibility. Users can still read the topic and its replies.</li><li>Merging topics is a one-way action. The source topic is removed and its replies are merged into the target.</li><li>Bulk moderation actions apply to all selected topics in the current forum.</li></ul>',46),r=[n];function l(s,p,d,c,h,g){return i(),o("div",null,r)}const f=e(a,[["render",l]]);export{u as __pageData,f as default};
